import React, { useEffect, useRef } from 'react';
import { X } from 'lucide-react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) {
      document.addEventListener('keydown', handleEscape);
      document.body.style.overflow = 'hidden';
    }
    return () => {
      document.removeEventListener('keydown', handleEscape);
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div 
        ref={modalRef}
        className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-200"
      >
        <div className="flex items-center justify-between p-4 border-b">
          <h3 className="text-lg font-semibold text-gray-900">{title}</h3>
          <button 
            onClick={onClose}
            className="p-1 rounded-full hover:bg-gray-100 transition-colors"
          >
            <X size={20} className="text-gray-500" />
          </button>
        </div>
        <div className="p-4 overflow-y-auto">
          {children}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Category } from '../types';
import { supabase } from '../services/supabase';
import { COLORS } from '../constants';
import { Trash2, Edit2, Plus, Check, X as XIcon } from 'lucide-react';

interface CategoryManagerProps {
  categories: Category[];
  onUpdate: () => void;
}

export const CategoryManager: React.FC<CategoryManagerProps> = ({ categories, onUpdate }) => {
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editName, setEditName] = useState('');
  const [editColor, setEditColor] = useState(COLORS[0]);
  const [isCreating, setIsCreating] = useState(false);

  const [newName, setNewName] = useState('');
  const [newColor, setNewColor] = useState(COLORS[0]);
  const [loading, setLoading] = useState(false);

  const handleDelete = async (id: number) => {
    if (!window.confirm('Êtes-vous sûr de vouloir supprimer cette catégorie ? Les articles associés seront conservés mais sans catégorie.')) return;

    setLoading(true);
    try {
      // First update items to remove category
      await supabase.from('stocks').update({ category_id: null }).eq('category_id', id);
      // Then delete category
      const { error } = await supabase.from('categories').delete().eq('id', id);
      if (error) throw error;
      onUpdate();
    } catch (err) {
      alert('Erreur lors de la suppression');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleStartEdit = (cat: Category) => {
    setEditingId(cat.id);
    setEditName(cat.name);
    setEditColor(cat.color);
    setIsCreating(false);
  };

  const handleSaveEdit = async () => {
    if (!editName.trim()) return;
    setLoading(true);
    try {
      const { error } = await supabase
        .from('categories')
        .update({ name: editName, color: editColor })
        .eq('id', editingId);

      if (error) throw error;
      setEditingId(null);
      onUpdate();
    } catch (err) {
      console.error(err);
      alert('Erreur lors de la modification');
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async () => {
    if (!newName.trim()) return;
    setLoading(true);
    try {
      const { error } = await supabase
        .from('categories')
        .insert([{ name: newName, color: newColor }]);

      if (error) throw error;
      setNewName('');
      setNewColor(COLORS[0]);
      setIsCreating(false);
      onUpdate();
    } catch (err) {
      console.error(err);
      alert('Erreur lors de la création');
    } finally {
      setLoading(false);
    }
  };

  const renderColorPicker = (selected: string, onSelect: (c: string) => void) => (
    <div className="flex flex-wrap gap-2 mt-2">
      {COLORS.map((c) => (
        <button
          key={c}
          type="button"
          onClick={() => onSelect(c)}
          className={`w-6 h-6 rounded-full border-2 transition-transform hover:scale-110 ${
            selected === c ? 'border-gray-800 scale-110 shadow-sm' : 'border-transparent'
          }`}
          style={{ backgroundColor: c }}
        />
      ))}
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-gray-800">Gérer les catégories</h2>
        {!isCreating && (
          <button
            onClick={() => setIsCreating(true)}
            className="flex items-center gap-2 px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium"
          >
            <Plus size={16} /> Nouvelle
          </button>
        )}
      </div>

      {isCreating && (
        <div className="bg-blue-50 p-4 rounded-xl border border-blue-100 animate-in fade-in slide-in-from-top-2">
          <div className="space-y-3">
            <div>
              <label className="block text-sm font-medium text-blue-900 mb-1">Nom</label>
              <input
                type="text"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                className="w-full p-2 border border-blue-200 rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Ex: Cuisine"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-blue-900 mb-1">Couleur</label>
              {renderColorPicker(newColor, setNewColor)}
            </div>
            <div className="flex justify-end gap-2 mt-4">
              <button
                onClick={() => setIsCreating(false)}
                className="px-3 py-1.5 text-gray-600 hover:bg-gray-100 rounded-md text-sm"
              >
                Annuler
              </button>
              <button
                onClick={handleCreate}
                disabled={loading || !newName.trim()}
                className="px-3 py-1.5 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50 text-sm font-medium"
              >
                {loading ? '...' : 'Créer'}
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="space-y-3">
        {categories.map((cat) => (
          <div 
            key={cat.id} 
            className="flex flex-col p-3 bg-white border border-gray-100 rounded-xl shadow-sm hover:shadow-md transition-shadow"
          >
            {editingId === cat.id ? (
              <div className="space-y-3">
                 <input
                    type="text"
                    value={editName}
                    onChange={(e) => setEditName(e.target.value)}
                    className="w-full p-2 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
                  />
                 {renderColorPicker(editColor, setEditColor)}
                 <div className="flex justify-end gap-2 pt-2">
                    <button
                      onClick={() => setEditingId(null)}
                      className="p-2 text-gray-500 hover:bg-gray-100 rounded-full"
                    >
                      <XIcon size={18} />
                    </button>
                    <button
                      onClick={handleSaveEdit}
                      disabled={loading}
                      className="p-2 bg-green-500 text-white rounded-full hover:bg-green-600 disabled:opacity-50"
                    >
                      <Check size={18} />
                    </button>
                 </div>
              </div>
            ) : (
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div 
                    className="w-4 h-4 rounded-full" 
                    style={{ backgroundColor: cat.color }}
                  />
                  <span className="font-medium text-gray-800">{cat.name}</span>
                </div>
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => handleStartEdit(cat)}
                    className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                  >
                    <Edit2 size={16} />
                  </button>
                  <button
                    onClick={() => handleDelete(cat.id)}
                    className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            )}
          </div>
        ))}
        {categories.length === 0 && !isCreating && (
          <p className="text-center text-gray-500 py-4 text-sm">Aucune catégorie définie</p>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { StockItem, Category } from '../types';
import { supabase } from '../services/supabase';
import { Modal } from './Modal';
import { Minus, Plus } from 'lucide-react';

interface StockItemModalProps {
  isOpen: boolean;
  onClose: () => void;
  item: StockItem | null; // null means create mode
  categories: Category[];
  currentCategoryId: number | null;
  onUpdate: () => void;
}

export const StockItemModal: React.FC<StockItemModalProps> = ({ 
  isOpen, 
  onClose, 
  item, 
  categories,
  currentCategoryId,
  onUpdate 
}) => {
  const [name, setName] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [categoryId, setCategoryId] = useState<number | null>(null);
  const [loading, setLoading] = useState(false);

  // Initialize form when item changes or modal opens
  useEffect(() => {
    if (isOpen) {
      if (item) {
        setName(item.name);
        setQuantity(item.quantity);
        setCategoryId(item.category_id);
      } else {
        setName('');
        setQuantity(1);
        // Default to current category selection if not "All" (null)
        setCategoryId(currentCategoryId);
      }
    }
  }, [isOpen, item, currentCategoryId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setLoading(true);
    try {
      const payload = {
        name,
        quantity,
        category_id: categoryId === 0 ? null : categoryId // 0 might come from select value "0" or "null" string conversion issues, safe check
      };

      if (item) {
        // Update
        const { error } = await supabase
          .from('stocks')
          .update(payload)
          .eq('id', item.id);
        if (error) throw error;
      } else {
        // Create
        const { error } = await supabase
          .from('stocks')
          .insert([payload]);
        if (error) throw error;
      }

      onUpdate();
      onClose();
    } catch (err) {
      console.error(err);
      alert('Une erreur est survenue');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!item) return;
    if (!window.confirm('Supprimer cet article ?')) return;

    setLoading(true);
    try {
      const { error } = await supabase.from('stocks').delete().eq('id', item.id);
      if (error) throw error;
      onUpdate();
      onClose();
    } catch (err) {
      console.error(err);
      alert('Erreur lors de la suppression');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal 
      isOpen={isOpen} 
      onClose={onClose} 
      title={item ? "Modifier l'article" : "Nouvel article"}
    >
      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Nom du produit</label>
          <input
            type="text"
            required
            autoFocus
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
            placeholder="Ex: Lait demi-écrémé"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Quantité</label>
          <div className="flex items-center gap-4">
            <button
              type="button"
              onClick={() => setQuantity(Math.max(0, quantity - 1))}
              className="p-2 rounded-lg bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors"
            >
              <Minus size={20} />
            </button>
            <input
              type="number"
              min="0"
              value={quantity}
              onChange={(e) => setQuantity(parseInt(e.target.value) || 0)}
              className="w-20 text-center p-2 text-lg font-semibold border-b-2 border-gray-200 focus:border-blue-500 outline-none"
            />
             <button
              type="button"
              onClick={() => setQuantity(quantity + 1)}
              className="p-2 rounded-lg bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors"
            >
              <Plus size={20} />
            </button>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Catégorie</label>
          <select
            value={categoryId ?? ''}
            onChange={(e) => {
              const val = e.target.value;
              setCategoryId(val === '' ? null : Number(val));
            }}
            className="w-full p-3 bg-white border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
          >
            <option value="">Aucune catégorie</option>
            {categories.map(cat => (
              <option key={cat.id} value={cat.id}>{cat.name}</option>
            ))}
          </select>
        </div>

        <div className="flex gap-3 pt-4 border-t">
          {item && (
            <button
              type="button"
              onClick={handleDelete}
              className="px-4 py-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors font-medium"
            >
              Supprimer
            </button>
          )}
          <div className="flex-1"></div>
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
          >
            Annuler
          </button>
          <button
            type="submit"
            disabled={loading}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-md transition-all font-medium disabled:opacity-50"
          >
            {loading ? 'Enregistrement...' : 'Enregistrer'}
          </button>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter } from 'react-router-dom';
import { supabase } from './services/supabase';
import { Category, StockItem } from './types';
import { CategoryManager } from './components/CategoryManager';
import { StockItemModal } from './components/StockItemModal';
import { Modal } from './components/Modal';
import { 
  Menu, 
  Settings, 
  Plus, 
  Search, 
  PackageOpen, 
  ChevronRight,
  Filter
} from 'lucide-react';
import { DEFAULT_CATEGORY_COLOR } from './constants';

function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [stocks, setStocks] = useState<StockItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategoryId, setSelectedCategoryId] = useState<number | null>(null); // null = All

  // UI States
  const [isCategoryModalOpen, setCategoryModalOpen] = useState(false);
  const [isStockModalOpen, setStockModalOpen] = useState(false);
  const [editingStock, setEditingStock] = useState<StockItem | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const fetchData = async () => {
    setLoading(true);
    try {
      const [catRes, stockRes] = await Promise.all([
        supabase.from('categories').select('*').order('name'),
        supabase.from('stocks').select('*').order('name')
      ]);

      if (catRes.error) throw catRes.error;
      if (stockRes.error) throw stockRes.error;

      setCategories(catRes.data || []);
      setStocks(stockRes.data || []);
    } catch (error) {
      console.error('Error fetching data:', error);
      // Fallback for demo purposes if tables don't exist yet to avoid white screen
      // but assuming correct Supabase setup as per prompt
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const filteredStocks = useMemo(() => {
    let result = stocks;

    // Filter by category
    if (selectedCategoryId !== null) {
      result = result.filter(s => s.category_id === selectedCategoryId);
    }

    // Filter by search
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(s => s.name.toLowerCase().includes(q));
    }

    return result;
  }, [stocks, selectedCategoryId, searchQuery]);

  const currentCategory = categories.find(c => c.id === selectedCategoryId);
  const currentColor = currentCategory?.color || DEFAULT_CATEGORY_COLOR;

  const handleOpenCreateStock = () => {
    setEditingStock(null);
    setStockModalOpen(true);
  };

  const handleEditStock = (item: StockItem) => {
    setEditingStock(item);
    setStockModalOpen(true);
  };

  // --- Components for Layout ---

  const CategoryList = () => (
    <nav className="space-y-1">
      <button
        onClick={() => setSelectedCategoryId(null)}
        className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
          selectedCategoryId === null 
            ? 'bg-blue-50 text-blue-700 shadow-sm font-semibold' 
            : 'text-gray-600 hover:bg-gray-100'
        }`}
      >
        <div className="w-2 h-2 rounded-full bg-gray-400" />
        <span className="flex-1 text-left">Tout le stock</span>
        <span className="text-xs text-gray-400 font-medium bg-gray-100 px-2 py-0.5 rounded-full">
          {stocks.length}
        </span>
      </button>

      {categories.map(cat => {
        const count = stocks.filter(s => s.category_id === cat.id).length;
        const isActive = selectedCategoryId === cat.id;
        return (
          <button
            key={cat.id}
            onClick={() => setSelectedCategoryId(cat.id)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              isActive 
                ? 'bg-white shadow-sm ring-1 ring-black/5' 
                : 'text-gray-600 hover:bg-gray-50'
            }`}
          >
            <div 
              className={`w-3 h-3 rounded-full shadow-sm ${isActive ? 'scale-125' : ''}`}
              style={{ backgroundColor: cat.color }}
            />
            <span className={`flex-1 text-left truncate ${isActive ? 'font-semibold text-gray-900' : ''}`}>
              {cat.name}
            </span>
             <span className="text-xs text-gray-400 font-medium bg-gray-100 px-2 py-0.5 rounded-full">
              {count}
            </span>
          </button>
        );
      })}
    </nav>
  );

  return (
    <div className="h-full flex flex-col md:flex-row bg-gray-50">
      {/* --- Desktop Sidebar --- */}
      <aside className="hidden md:flex w-72 flex-col bg-white border-r border-gray-200 h-full">
        <div className="p-6 border-b border-gray-100">
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <PackageOpen className="text-blue-600" />
            HomeStock
          </h1>
        </div>

        <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
          <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-4 px-2">Catégories</div>
          <CategoryList />
        </div>

        <div className="p-4 border-t border-gray-100 bg-gray-50/50">
          <button
            onClick={() => setCategoryModalOpen(true)}
            className="w-full flex items-center justify-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 hover:text-blue-600 transition-colors shadow-sm"
          >
            <Settings size={16} />
            Gérer les catégories
          </button>
        </div>
      </aside>

      {/* --- Mobile Header --- */}
      <header className="md:hidden bg-white border-b border-gray-200 sticky top-0 z-30 shadow-sm">
        <div className="px-4 py-3 flex items-center gap-3">
          <div className="flex-1 relative">
             {/* Mobile Dropdown for Categories */}
             <div className="relative">
                <select
                  value={selectedCategoryId ?? 'all'}
                  onChange={(e) => setSelectedCategoryId(e.target.value === 'all' ? null : Number(e.target.value))}
                  className="appearance-none w-full pl-10 pr-8 py-2.5 bg-gray-100 border-transparent rounded-xl text-gray-900 font-semibold focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition-all"
                >
                  <option value="all">Tout le stock</option>
                  {categories.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                  ))}
                </select>
                <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none">
                   {selectedCategoryId === null ? (
                      <PackageOpen size={18} className="text-gray-500" />
                   ) : (
                      <div 
                        className="w-4 h-4 rounded-full shadow-sm" 
                        style={{ backgroundColor: currentColor }} 
                      />
                   )}
                </div>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-gray-500">
                  <Filter size={16} />
                </div>
             </div>
          </div>

          <button
            onClick={() => setCategoryModalOpen(true)}
            className="p-2.5 bg-gray-100 text-gray-600 rounded-xl hover:bg-gray-200 active:scale-95 transition-all"
          >
            <Settings size={20} />
          </button>
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="flex-1 h-full overflow-hidden flex flex-col relative">
        {/* Header / Search Area */}
        <div className="p-4 md:p-8 pb-0 md:pb-4">
           <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
              <div>
                <h2 className="text-2xl font-bold text-gray-900 hidden md:block">
                  {selectedCategoryId === null ? 'Tout le stock' : currentCategory?.name}
                </h2>
                <p className="text-gray-500 text-sm hidden md:block">
                  {filteredStocks.length} article{filteredStocks.length !== 1 ? 's' : ''} trouvé{filteredStocks.length !== 1 ? 's' : ''}
                </p>
              </div>

              <div className="relative w-full md:w-80">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input
                  type="text"
                  placeholder="Rechercher un produit..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none shadow-sm transition-all"
                />
              </div>
           </div>
        </div>

        {/* Scrollable Stock List */}
        <div className="flex-1 overflow-y-auto px-4 md:px-8 pb-24 md:pb-8">
          {loading ? (
             <div className="flex justify-center items-center h-40">
               <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
             </div>
          ) : filteredStocks.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-gray-400">
              <PackageOpen size={48} className="mb-4 opacity-50" />
              <p className="text-lg font-medium">Aucun article trouvé</p>
              {searchQuery && <p className="text-sm mt-1">Essayez une autre recherche</p>}
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 md:gap-4">
              {filteredStocks.map(stock => {
                const cat = categories.find(c => c.id === stock.category_id);
                const color = cat?.color || DEFAULT_CATEGORY_COLOR;

                return (
                  <div
                    key={stock.id}
                    onClick={() => handleEditStock(stock)}
                    className="group bg-white p-4 rounded-xl shadow-sm border border-gray-100 hover:shadow-md hover:border-blue-200 transition-all cursor-pointer relative overflow-hidden"
                  >
                    <div 
                      className="absolute left-0 top-0 bottom-0 w-1.5" 
                      style={{ backgroundColor: color }}
                    />
                    <div className="pl-3">
                      <div className="flex justify-between items-start mb-1">
                        <span className="text-xs font-semibold px-2 py-0.5 rounded-full bg-gray-50 text-gray-500 truncate max-w-[70%]">
                           {cat?.name || 'Sans catégorie'}
                        </span>
                      </div>
                      <h3 className="font-bold text-gray-900 text-lg mb-1 line-clamp-2 leading-tight">
                        {stock.name}
                      </h3>
                      <div className="flex items-center text-gray-600 mt-2">
                        <span className="text-2xl font-bold text-gray-800 mr-1.5">
                           {stock.quantity}
                        </span>
                        <span className="text-sm font-medium text-gray-400">en stock</span>
                      </div>
                    </div>
                    <div className="absolute right-3 bottom-3 opacity-0 group-hover:opacity-100 transition-opacity transform translate-x-2 group-hover:translate-x-0">
                      <ChevronRight className="text-blue-500" size={20} />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Floating Action Button (Mobile & Desktop) */}
        <button
          onClick={handleOpenCreateStock}
          className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-14 h-14 bg-blue-600 text-white rounded-full shadow-lg shadow-blue-600/30 flex items-center justify-center hover:bg-blue-700 hover:scale-105 active:scale-95 transition-all z-20"
          aria-label="Ajouter un article"
        >
          <Plus size={28} strokeWidth={2.5} />
        </button>
      </main>

      {/* --- Modals --- */}
      <Modal
        isOpen={isCategoryModalOpen}
        onClose={() => setCategoryModalOpen(false)}
        title="Paramètres"
      >
        <CategoryManager
          categories={categories}
          onUpdate={fetchData}
        />
      </Modal>

      <StockItemModal
        isOpen={isStockModalOpen}
        onClose={() => setStockModalOpen(false)}
        item={editingStock}
        categories={categories}
        currentCategoryId={selectedCategoryId}
        onUpdate={fetchData}
      />
    </div>
  );
}

