      <Modal
        isOpen={isCategoryModalOpen}
        onClose={() => setCategoryModalOpen(false)}
        title="Paramètres"
      >
        <CategoryManager
          categories={categories}
          onUpdate={fetchData}
        />
      </Modal>

      <StockItemModal
        isOpen={isStockModalOpen}
        onClose={() => setStockModalOpen(false)}
        item={editingStock}
        categories={categories}
        currentCategoryName={selectedCategoryName}
        onUpdate={fetchData}
      />
    </div>
  );
}

