import React, { useState, useEffect } from 'react';
import { StockItem, Category } from '../types';
import { supabase } from '../services/supabase';
import { Modal } from './Modal';
import { Minus, Plus } from 'lucide-react';

interface StockItemModalProps {
  isOpen: boolean;
  onClose: () => void;
  item: StockItem | null; // null means create mode
  categories: Category[];
  currentCategoryName: string | null;
  onUpdate: () => void;
}

// Fonction utilitaire pour générer un UUID si la base de données ne le fait pas automatiquement
const generateUUID = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};

export const StockItemModal: React.FC<StockItemModalProps> = ({ 
  isOpen, 
  onClose, 
  item, 
  categories,
  currentCategoryName,
  onUpdate 
}) => {
  const [produit, setProduit] = useState('');
  const [quantite, setQuantite] = useState(1);
  const [categorieName, setCategorieName] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  // Initialize form when item changes or modal opens
  useEffect(() => {
    if (isOpen) {
      if (item) {
        setProduit(item.produit);
        setQuantite(item.quantite);
        setCategorieName(item.categorie);
      } else {
        setProduit('');
        setQuantite(1);
        // Default to current category selection if available
        setCategorieName(currentCategoryName);
      }
    }
  }, [isOpen, item, currentCategoryName]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!produit.trim()) return;

    setLoading(true);
    try {
      const basePayload = {
        produit: produit.trim(),
        quantite: Math.max(0, Math.floor(quantite)), // Ensure positive integer
        categorie: !categorieName ? null : categorieName // Ensure null if empty
      };

      if (item) {
        // Update
        const { error } = await supabase
          .from('stocks')
          .update(basePayload)
          .eq('id', item.id);
        if (error) throw error;
      } else {
        // Create - On génère l'ID manuellement car la BDD semble ne pas avoir de valeur par défaut
        const createPayload = {
          ...basePayload,
          id: generateUUID()
        };

        const { error } = await supabase
          .from('stocks')
          .insert([createPayload])
          .select(); // Add select to verify insertion
        if (error) throw error;
      }

      onUpdate();
      onClose();
    } catch (err: any) {
      console.error('Erreur sauvegarde:', err);
      // Affiche le message d'erreur précis pour aider au débogage
      alert(`Erreur lors de l'enregistrement : ${err.message || err.error_description || 'Erreur inconnue'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!item) return;
    if (!window.confirm('Supprimer cet article ?')) return;

    setLoading(true);
    try {
      const { error } = await supabase.from('stocks').delete().eq('id', item.id);
      if (error) throw error;
      onUpdate();
      onClose();
    } catch (err: any) {
      console.error(err);
      alert(`Erreur lors de la suppression : ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal 
      isOpen={isOpen} 
      onClose={onClose} 
      title={item ? "Modifier l'article" : "Nouvel article"}
    >
      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Nom du produit</label>
          <input
            type="text"
            required
            autoFocus
            value={produit}
            onChange={(e) => setProduit(e.target.value)}
            className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
            placeholder="Ex: Lait demi-écrémé"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Quantité</label>
          <div className="flex items-center gap-4">
            <button
              type="button"
              onClick={() => setQuantite(Math.max(0, quantite - 1))}
              className="p-2 rounded-lg bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors"
            >
              <Minus size={20} />
            </button>
            <input
              type="number"
              min="0"
              value={quantite}
              onChange={(e) => setQuantite(parseInt(e.target.value) || 0)}
              className="w-20 text-center p-2 text-lg font-semibold border-b-2 border-gray-200 focus:border-blue-500 outline-none"
            />
             <button
              type="button"
              onClick={() => setQuantite(quantite + 1)}
              className="p-2 rounded-lg bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors"
            >
              <Plus size={20} />
            </button>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Catégorie</label>
          <select
            value={categorieName ?? ''}
            onChange={(e) => {
              const val = e.target.value;
              setCategorieName(val === '' ? null : val);
            }}
            className="w-full p-3 bg-white border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
          >
            <option value="">Aucune catégorie</option>
            {categories.map(cat => (
              <option key={cat.id} value={cat.name}>{cat.name}</option>
            ))}
          </select>
        </div>

        <div className="flex gap-3 pt-4 border-t">
          {item && (
            <button
              type="button"
              onClick={handleDelete}
              className="px-4 py-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors font-medium"
            >
              Supprimer
            </button>
          )}
          <div className="flex-1"></div>
          <button
            type="button"
            onClick={onClose}
            className="px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
          >
            Annuler
          </button>
          <button
            type="submit"
            disabled={loading}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-md transition-all font-medium disabled:opacity-50"
          >
            {loading ? 'Enregistrement...' : 'Enregistrer'}
          </button>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter } from 'react-router-dom';
import { supabase } from './services/supabase';
import { Category, StockItem } from './types';
import { CategoryManager } from './components/CategoryManager';
import { StockItemModal } from './components/StockItemModal';
import { Modal } from './components/Modal';
import { 
  Settings, 
  Plus, 
  Minus,
  Search, 
  PackageOpen, 
  Filter,
  RefreshCw,
  AlertCircle
} from 'lucide-react';
import { DEFAULT_CATEGORY_COLOR } from './constants';

function App() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [stocks, setStocks] = useState<StockItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  // We track selection by Category Name because the stocks table links by name, not ID
  const [selectedCategoryName, setSelectedCategoryName] = useState<string | null>(null); 

  // UI States
  const [isCategoryModalOpen, setCategoryModalOpen] = useState(false);
  const [isStockModalOpen, setStockModalOpen] = useState(false);
  const [editingStock, setEditingStock] = useState<StockItem | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const fetchData = async () => {
    setLoading(true);
    setError(null);
    try {
      // Order by name/produit
      const [catRes, stockRes] = await Promise.all([
        supabase.from('categories').select('*').order('name'),
        supabase.from('stocks').select('*').order('produit')
      ]);

      if (catRes.error) throw new Error(`Erreur catégories: ${catRes.error.message}`);
      if (stockRes.error) throw new Error(`Erreur stocks: ${stockRes.error.message}`);

      setCategories(catRes.data || []);
      setStocks(stockRes.data || []);
    } catch (err: any) {
      console.error('Error fetching data:', err);
      setError(err.message || 'Impossible de se connecter à la base de données');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const updateQuantity = async (e: React.MouseEvent, item: StockItem, delta: number) => {
    e.stopPropagation(); // Prevent opening the modal
    const newQuantity = Math.max(0, item.quantite + delta);

    if (newQuantity === item.quantite) return;

    // Optimistic Update: Update UI immediately
    setStocks(prev => prev.map(s => 
      s.id === item.id ? { ...s, quantite: newQuantity } : s
    ));

    try {
      const { error } = await supabase
        .from('stocks')
        .update({ quantite: newQuantity })
        .eq('id', item.id);

      if (error) throw error;
    } catch (err) {
      console.error("Error updating quantity:", err);
      // Revert on error by refetching
      fetchData();
    }
  };

  const filteredStocks = useMemo(() => {
    let result = stocks;

    // Filter by category name
    if (selectedCategoryName !== null) {
      result = result.filter(s => s.categorie === selectedCategoryName);
    }

    // Filter by search
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(s => s.produit.toLowerCase().includes(q));
    }

    return result;
  }, [stocks, selectedCategoryName, searchQuery]);

  // Find category object for color display
  const currentCategory = categories.find(c => c.name === selectedCategoryName);
  const currentColor = currentCategory?.color || DEFAULT_CATEGORY_COLOR;

  const handleOpenCreateStock = () => {
    setEditingStock(null);
    setStockModalOpen(true);
  };

  const handleEditStock = (item: StockItem) => {
    setEditingStock(item);
    setStockModalOpen(true);
  };

  // --- Components for Layout ---

  const CategoryList = () => (
    <nav className="space-y-1">
      <button
        onClick={() => setSelectedCategoryName(null)}
        className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
          selectedCategoryName === null 
            ? 'bg-blue-50 text-blue-700 shadow-sm font-semibold' 
            : 'text-gray-600 hover:bg-gray-100'
        }`}
      >
        <div className="w-2 h-2 rounded-full bg-gray-400" />
        <span className="flex-1 text-left">Tout le stock</span>
        <span className="text-xs text-gray-400 font-medium bg-gray-100 px-2 py-0.5 rounded-full">
          {stocks.length}
        </span>
      </button>

      {categories.map(cat => {
        // Count stocks that match this category NAME
        const count = stocks.filter(s => s.categorie === cat.name).length;
        const isActive = selectedCategoryName === cat.name;
        return (
          <button
            key={cat.id}
            onClick={() => setSelectedCategoryName(cat.name)}
