                              <Minus size={16} strokeWidth={2.5} />
                           </button>
                           <span className="w-8 text-center font-bold text-gray-800 text-lg">
                              {stock.quantite}
                           </span>
                           <button 
                              onClick={(e) => updateQuantity(e, stock, 1)}
